    console.log((idx + 1) + '. ' + nb.title + ' [' + nb.category + '] - ' + nb.sourceCount + ' 个来源');
  });
}

main().catch((error) => {
  console.error('\\n❌ ' + error.message);
  process.exit(1);
});

