/**
 * 将数据保存到本地
 * 路径格式: notex/{sessionid}/RT01/年月日时分秒xxx.md
 */
function saveToLocalFile(data, args) {
  const sessionId = args['session-id'] || 'default_session';
  const timestamp = new Date().toISOString().replace(/[-:T]/g, '').slice(0, 14);
  const randomSuffix = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
  const filename = `${timestamp}${randomSuffix}.md`;

  // 获取当前工作目录下的 notex 目录
  const projectRoot = process.cwd();
  const dirPath = path.join(projectRoot, 'notex', sessionId, 'RT01');

  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }

  const filePath = path.join(dirPath, filename);
  const content = typeof data === 'string' ? data : JSON.stringify(data, null, 2);

  fs.writeFileSync(filePath, content, 'utf8');

  return path.relative(projectRoot, filePath);
}

