              "type": "text",
              "text": "【main】可以，给你一版**可直接跑**的 Python 日志分析脚本（先通用，后面我再按你日志格式精调）。\n\n```python\n#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\n\"\"\"\n用法：\npython log_analyzer.py app.log --top 20 --slow-ms 1000\npython log_analyzer.py app.log --from \"2026-03-06 00:00:00\" --to \"2026-03-06 23:59:59\"\n\"\"\"\n\nimport re\nimport argparse\nfrom collections import Counter, defaultdict\nfrom datetime import datetime\n\n# 示例日志格式（可改）：\n# 2026-03-06 10:12:31,123 INFO request_id=abc123 user=u1 method=GET path=/api/task status=200 cost_ms=345\nLOG_RE = re.compile(\n    r'^(?P<ts>\\d{4}-\\d{2}-\\d{2} \\d{2}:\\d{2}:\\d{2}),\\d+\\s+\\w+\\s+.*?'\n    r'method=(?P<method>[A-Z]+)\\s+path=(?P<path>\\S+)\\s+status=(?P<status>\\d{3})\\s+cost_ms=(?P<cost>\\d+)'\n)\n\ndef parse_ts(s: str):\n    return datetime.strptime(s, \"%Y-%m-%d %H:%M:%S\")\n\ndef percentile(values, p):\n    if not values:\n        return 0\n    arr = sorted(values)\n    k = (len(arr) - 1) * p\n    f = int(k)\n    c = min(f + 1, len(arr) - 1)\n    if f == c:\n        return arr[f]\n    return arr[f] + (arr[c] - arr[f]) * (k - f)\n\ndef main():\n    ap = argparse.ArgumentParser()\n    ap.add_argument(\"file\", help=\"日志文件路径\")\n    ap.add_argument(\"--top\", type=int, default=10, help=\"Top N 慢接口\")\n    ap.add_argument(\"--slow-ms\", type=int, default=1000, help=\"慢请求阈值(ms)\")\n    ap.add_argument(\"--from\", dest=\"from_ts\", help='起始时间，如 \"2026-03-06 00:00:00\"')\n    ap.add_argument(\"--to\", dest=\"to_ts\", help='结束时间，如 \"2026-03-06 23:59:59\"')\n    args = ap.parse_args()\n\n    from_dt = parse_ts(args.from_ts) if args.from_ts else None\n    to_dt = parse_ts(args.to_ts) if args.to_ts else None\n\n    total = 0\n    parsed = 0\n    status_counter = Counter()\n    endpoint_costs = defaultdict(list)\n    slow_counter = Counter()\n\n    with open(args.file, \"r\", encoding=\"utf-8\", errors=\"ignore\") as f:\n        for line in f:\n            total += 1\n            m = LOG_RE.search(line)\n            if not