function printUsage() {
  console.log(`
用法:
  # 获取笔记本列表
  node docs/skills/scripts/notebooks/notebooks-read.js --mode list-notebooks --key <CWorkKey>

  # 获取 Notebook 下来源列表（不含正文）
  node docs/skills/scripts/notebooks/notebooks-read.js --mode list --key <CWorkKey> --notebook-id <nbId>

  # 获取单个来源正文
  node docs/skills/scripts/notebooks/notebooks-read.js --mode content --key <CWorkKey> --notebook-id <nbId> --source-id <srcId>

可选参数:
  --key <CWorkKey>            CWork Key（推荐；脚本内部自动换取授权）
  --mode <list-notebooks|list|content>  list-notebooks=笔记本列表，list=来源列表，content=获取正文
  --notebook-id <id>          目标 Notebook ID（mode=list/content 必填）
  --source-id <id>            目标 Source ID（mode=content 必填）
  --session-id <id>           会话 ID（用于生成存储路径，默认 default_session）
  --business-type <type>      业务类型筛选（mode=list 可选）
  --category <category>       分类筛选（mode=list-notebooks 可选）
  --page <num>                页码（mode=list-notebooks 可选）
  --pageSize <num>            每页数量（mode=list-notebooks 可选）
  --base-url <url>            生产地址（仅支持 https://notex.aishuo.co/noteX 或 /noteX/openapi）
`);
}

async function main() {
  const args = parseArgs();
  const mode = args.mode;

  if (args.help || !mode) {
    printUsage();
    return;
  }

  if (mode !== 'list-notebooks' && mode !== 'list' && mode !== 'content') {
    printUsage();
    throw new Error(`不支持的 mode: ${mode}`);
  }

  await resolveAuthContext(args);

  if (mode === 'list-notebooks') {
    await listNotebooks(args);
    return;
  }

  if (mode === 'list') {
    await listSources(args);
    return;
  }

  await fetchSourceContent(args);
}

main().catch((error) => {
